ItemDef.redcap:Calculation:
if(
    [demog_birthknow]='1',
    datediff(
        [demog_birthdate],
        if([pres_date]='',"today",[pres_date]),
        "d",
        "dmy"
    ),
    if(
        [demog_age_units]='1',
        [demog_age]*365,
        if(
            [demog_age_units]='2',
            round([demog_age]*365/12,0),
            if(
                [demog_age_units]='3',
                [demog_age],
                ''
            )
        )
    )
)
